// Separate data
const contacts = items.filter(i => i.json.Id && !i.json.UnitPrice);
const products = items.filter(i => i.json.UnitPrice !== undefined);

// Calculations
const contactsCount = contacts.length;
const productsCount = products.length;

const totalProductValue = products.reduce((sum, p) => {
  return sum + (p.json.UnitPrice || 0);
}, 0);

// Return only calculated values
return [{
  json: {
    contacts: contactsCount,
    products: productsCount,
    totalProductValue
  }
}];

parameters.text:
=You are a sales operations expert.

Classify deal complexity based on:
- Deal amount
- Number of stakeholders
- Number of products
- Total product value
- Customization level

Guidelines:
- High: Large deal OR many stakeholders OR many products OR high total product value OR high customization
- Medium: Moderate deal size, moderate stakeholders/products/value, or medium customization
- Low: Small deal with few stakeholders/products/value and low customization

Input:
Deal Name: {{ $('Fetch Opportunity Details').item.json.Name }}
Amount: {{ $('Fetch Opportunity Details').item.json.Amount }}
Stakeholders: {{$json["contacts"]}}
Products: {{$json["products"]}}
Total Product Value: {{$json["totalProductValue"]}}
Customization:{{ $('Fetch Opportunity Details').item.json.Customization__c }}

Return STRICT JSON:
{
  "complexity": "Low/Medium/High",
  "reason": "short explanation",
  "actions": ["action1", "action2"]
}

parameters.jsCode:
const response = $json.output || $json.text || "";

// Extract JSON safely
let parsed;

try {
  parsed = JSON.parse(response);
} catch (e) {
  // fallback if AI adds extra text
  const match = response.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
}

return [{
  json: {
    complexity: parsed.complexity || "Medium",
    reason: parsed.reason || "No clear reason provided",
    actions: parsed.actions || ["Review deal manually"]
  }
}];

